mapper.select:
SELECT l.log_code AS logCode, l.project_code AS projectCode, p.project_name AS projectName,
l.action_type AS actionType, l.target_type AS targetType, l.target_code AS targetCode,
i.title AS issueTitle, l.created_at AS createdAt, l.meta AS meta FROM logs l JOIN projects p ON p.project_code = l.project_code LEFT JOIN issues i ON i.issue_code = l.target_code WHERE l.user_code = #{userCode} AND l.target_type = 'ISSUE' AND i.issue_code IS NOT NULL AND p.status = 'OD1'
AND l.project_code IN
#{pc}
AND l.created_at >= #{from}
AND l.created_at <= #{to}
ORDER BY l.created_at DESC
